import React, { useEffect, useState } from "react";
import "./HomePage.css";
import Main from "../../Components/Main/Main";
import Home from "../../Components/Home/Home";
import Loading from "../Loading/Loading";

function HomePage() {
  const [loading, setLoading] = useState(true);
  const [homeSliderData, setHomeSliderData] = useState(null);
  const [productsData, setProductsData] = useState(null);
  const [imagesLoaded, setImagesLoaded] = useState(0);
  const [totalImages, setTotalImages] = useState(0);

  useEffect(() => {
    window.scrollTo(0, 0);

    const fetchData = async () => {
      try {
        const { HomeSlider } = await import("../../Data/SliderImages");
        const { ProductsData } = await import("../../Data/ProductsData");

        setHomeSliderData(HomeSlider);
        setProductsData(ProductsData);

        // Calculate total images after data is fetched
        const homeImages = HomeSlider.length;
        const productImages = ProductsData.flatMap((product) => product.Images).length;

        setTotalImages(homeImages + productImages);
        console.log("Total Images to Load:", homeImages + productImages);
      } catch (error) {
        console.error("Error loading data:", error);
      }
    };

    fetchData();
  }, []);

  const handleImageLoad = () => {
    setImagesLoaded((prev) => {
      const newCount = prev + 1;
      console.log("Images Loaded:", newCount);
      return newCount;
    });
  };

  const handleImageError = () => {
    setImagesLoaded((prev) => {
      const newCount = prev + 1;
      console.warn("Image failed to load. Incrementing loaded count:", newCount);
      return newCount;
    });
  };

  useEffect(() => {
    if (imagesLoaded === totalImages && totalImages > 0) {
      console.log("All images loaded. Stopping spinner.");
      setLoading(false);
    }
  }, [imagesLoaded, totalImages]);

  if (loading) {
    return <Loading />;
  }

  return (
    <div className="background">
      <Home
        slides={homeSliderData}
        onImageLoad={handleImageLoad}
        onImageError={handleImageError}
      />
      <Main
        images={productsData}
        onImageLoad={handleImageLoad}
        onImageError={handleImageError}
      />
    </div>
  );
}

export default HomePage;





